session_start(); date_default_timezone_set('Asia/Jakarta'); ini_set('display_errors','0'); error_reporting(E_ALL); if(!defined('APP_INIT')){ define('APP_INIT', true); } function app_path($p){ return __DIR__ . '/' . ltrim($p,'/'); } function db(){ static $pdo = null; if($pdo !== null){ return $pdo; } $dir = app_path('data'); if(!is_dir($dir)){ @mkdir($dir,0755,true); } $pdo = new PDO('sqlite:' . app_path('data/sinu_absensi.sqlite')); $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION); $pdo->exec('PRAGMA journal_mode=WAL'); install_db($pdo); return $pdo; } function install_db($pdo){ $pdo->exec("CREATE TABLE IF NOT EXISTS users(
      id INTEGER PRIMARY KEY AUTOINCREMENT, role TEXT DEFAULT 'pegawai', name TEXT, username TEXT UNIQUE,
      password TEXT, phone TEXT, position TEXT, avatar TEXT, status TEXT DEFAULT 'aktif', created_at TEXT
    )"); $pdo->exec("CREATE TABLE IF NOT EXISTS settings(k TEXT PRIMARY KEY, v TEXT)"); $pdo->exec("CREATE TABLE IF NOT EXISTS attendance(
      id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER, type TEXT, lat REAL, lng REAL, distance_m REAL,
      inside_area INTEGER, photo TEXT, note TEXT, created_at TEXT
    )"); $pdo->exec("CREATE TABLE IF NOT EXISTS leaves(
      id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER, kind TEXT, date_start TEXT, date_end TEXT, reason TEXT, status TEXT DEFAULT 'Menunggu', created_at TEXT
    )"); $pdo->exec("CREATE TABLE IF NOT EXISTS logs(id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER, action TEXT, ip TEXT, ua TEXT, created_at TEXT)"); $count = intval($pdo->query("SELECT COUNT(*) FROM users")->fetchColumn()); if($count < 1){ $now = date('Y-m-d H:i:s'); $st = $pdo->prepare("INSERT INTO users(role,name,username,password,phone,position,avatar,status,created_at) VALUES(?,?,?,?,?,?,?,?,?)"); $defaultAdminPass = password_hash('ChangeMeAdmin@2026', PASSWORD_DEFAULT); $defaultPegawaiPass = password_hash('ChangeMePegawai@2026', PASSWORD_DEFAULT); $st->execute(array('admin','Administrator','admin',$defaultAdminPass,'0882010005000','Admin Sistem','','aktif',$now)); $st->execute(array('pegawai','doni','pegawai',$defaultPegawaiPass,'081234567890','Pegawai Kantor Pusat','assets/avatar.png','aktif',$now)); } try{ $chk=$pdo->prepare("SELECT id FROM users WHERE username='haruki' LIMIT 1"); $chk->execute(); $old=$chk->fetchColumn(); if($old){ $up=$pdo->prepare("UPDATE users SET name=?, username=?, password=? WHERE id=?"); $up->execute(array('doni','pegawai',password_hash('ChangeMePegawai@2026', PASSWORD_DEFAULT),$old)); } }catch(Exception $e){} $defaults = array( 'app_name'=>'SINU Attendance', 'org_name'=>'Sinu School', 'greeting_name'=>'doni', 'date_label'=>'Kamis, 7 Mei 2026', 'office_name'=>'Kantor Pusat', 'office_address'=>'Jl. Merdeka No. 10, Kota Bandung', 'office_lat'=>'-6.914744', 'office_lng'=>'107.609810', 'radius_m'=>'250', 'map_note'=>'Alun-Alun Kota', 'avatar_img'=>'assets/avatar.png', 'hero_img'=>'assets/hero_boy.png', 'status_img'=>'assets/status_face.png', 'map_img'=>'assets/map_ref.png', 'accent'=>'#17d9ff', 'lock_employee_status'=>'1', 'lock_maps'=>'1', 'lock_face'=>'1' ); $st = $pdo->prepare("INSERT OR IGNORE INTO settings(k,v) VALUES(?,?)"); foreach($defaults as $k=>$v){ $st->execute(array($k,$v)); } try{ $pdo->exec("DELETE FROM users WHERE role='pegawai' AND username<>'pegawai'"); $stOne=$pdo->prepare("SELECT id FROM users WHERE username='pegawai' LIMIT 1"); $stOne->execute(); $one=$stOne->fetchColumn(); if($one){ $up=$pdo->prepare("UPDATE users SET role='pegawai',name='doni',password=?,phone='081234567890',position='Pegawai Kantor Pusat',status='aktif',avatar='assets/avatar.png' WHERE id=?"); $up->execute(array(password_hash('ChangeMePegawai@2026',PASSWORD_DEFAULT),$one)); } else { $ins=$pdo->prepare("INSERT INTO users(role,name,username,password,phone,position,avatar,status,created_at) VALUES('pegawai','doni','pegawai',?,?,?,?,?)"); $ins->execute(array(password_hash('ChangeMePegawai@2026',PASSWORD_DEFAULT),'081234567890','Pegawai Kantor Pusat','assets/avatar.png','aktif',date('Y-m-d H:i:s'))); } }catch(Exception $e){} set_setting('date_label','Kamis, 7 Mei 2026'); } function setting($k){ $st = db()->prepare("SELECT v FROM settings WHERE k=?"); $st->execute(array($k)); $v = $st->fetchColumn(); return $v === false ? '' : $v; } function set_setting($k,$v){ $st=db()->prepare("INSERT OR REPLACE INTO settings(k,v) VALUES(?,?)"); $st->execute(array($k,$v)); } function e($s){ return htmlspecialchars((string)$s, ENT_QUOTES, 'UTF-8'); } function csrf_token(){ if(empty($_SESSION['csrf'])){ $_SESSION['csrf']=bin2hex(openssl_random_pseudo_bytes(16)); } return $_SESSION['csrf']; } function csrf_check(){ if($_SERVER['REQUEST_METHOD']==='POST'){ $t=isset($_POST['csrf'])?$_POST['csrf']:''; if(empty($_SESSION['csrf']) || !hash_equals($_SESSION['csrf'],$t)){ json_out(array('ok'=>false,'message'=>'Sesi tidak valid. Muat ulang halaman.'),403); } } } function json_out($arr,$code=200){ http_response_code($code); header('Content-Type: application/json; charset=utf-8'); echo json_encode($arr); exit; } function current_user(){ return isset($_SESSION['user']) ? $_SESSION['user'] : null; } function feature_locked($k){ return setting($k)==='1'; } function require_login(){ if(!current_user()){ header('Location: index.php'); exit; } } function require_admin(){ require_login(); if($_SESSION['user']['role']!=='admin'){ header('Location: index.php'); exit; } } function log_action($action,$uid){ $st=db()->prepare("INSERT INTO logs(user_id,action,ip,ua,created_at) VALUES(?,?,?,?,?)"); $st->execute(array($uid,$action,isset($_SERVER['REMOTE_ADDR'])?$_SERVER['REMOTE_ADDR']:'',isset($_SERVER['HTTP_USER_AGENT'])?substr($_SERVER['HTTP_USER_AGENT'],0,180):'',date('Y-m-d H:i:s'))); } function distance_m($lat1,$lon1,$lat2,$lon2){ $r=6371000; $p1=deg2rad($lat1); $p2=deg2rad($lat2); $dp=deg2rad($lat2-$lat1); $dl=deg2rad($lon2-$lon1); $a=sin($dp/2)*sin($dp/2)+cos($p1)*cos($p2)*sin($dl/2)*sin($dl/2); return $r*2*atan2(sqrt($a),sqrt(1-$a)); } function validate_gps($lat,$lng){ if(!is_numeric($lat) || !is_numeric($lng)){ return false; } $lat = floatval($lat); $lng = floatval($lng); return $lat >= -90 && $lat <= 90 && $lng >= -180 && $lng <= 180; } function validate_date($date){ $d = \DateTime::createFromFormat('Y-m-d', $date); return $d && $d->format('Y-m-d') === $date; } function validate_password($password){ return strlen(trim($password)) >= 6; } function upload_img($field,$old){ if(empty($_FILES[$field]) || $_FILES[$field]['error']!==UPLOAD_ERR_OK){ return $old; } $file = $_FILES[$field]; $max_size = 5242880; if($file['size'] > $max_size){ return $old; } $info = @getimagesize($file['tmp_name']); if(!$info || !in_array($info['mime'], array('image/png','image/jpeg','image/webp'))){ return $old; } $ext = $info['mime']==='image/png' ? 'png' : ($info['mime']==='image/webp' ? 'webp' : 'jpg'); $width = $info[0]; $height = $info[1]; if($width < 50 || $height < 50 || $width > 4000 || $height > 4000){ return $old; } $name = 'uploads/settings/'.date('YmdHis').'_'.$field.'.'.$ext; if(@move_uploaded_file($file['tmp_name'], app_path($name))){ return $name; } return $old; } try{ db(); }catch(Exception $e){ @file_put_contents(app_path('data/error.log'),date('c').' '.$e->getMessage()."\n",FILE_APPEND); die('Aplikasi sedang menyiapkan data. Refresh halaman.'); } 